# Category: insecure_coap

import network, time, machine
from microcoapy import Coap, CoapMessage, MessageType, Method, ResponseCode

# --- OPTIONAL: Wi-Fi setup ---------------------------------------------------
SSID     = 'YOUR_SSID'
PASSWORD = 'YOUR_PASS'

def wifi_connect():
    sta = network.WLAN(network.STA_IF)
    if not sta.isconnected():
        sta.active(True)
        sta.connect(SSID, PASSWORD)
        while not sta.isconnected():
            time.sleep_ms(200)

try:
    wifi_connect()
except:
    pass
# ---------------------------------------------------------------------------

# --- Hardware bindings ------------------------------------------------------
LED_PIN = 2                                 # change if your board uses another pin
led     = machine.Pin(LED_PIN, machine.Pin.OUT)

def read_temp():
    try:
        import esp32
        return esp32.raw_temperature() / 10.0
    except:
        return 24.0
# ---------------------------------------------------------------------------

coap = Coap()

def _build_response(req, code, payload=b''):
    rsp           = CoapMessage(msg_type=MessageType.ACK,
                                msg_code=code,
                                payload=payload)
    rsp.msg_id    = req.msg_id
    rsp.token     = req.token
    return rsp

# /sensors/temp --------------------------------------------------------------
def sensors_temp(req, addr):
    if req.code == Method.GET:
        temp     = ('%.1f' % read_temp()).encode()
        response = _build_response(req, ResponseCode.CONTENT, temp)
    else:
        response = _build_response(req, ResponseCode.METHOD_NOT_ALLOWED)
    coap.send_response(addr, response)

# /actuators/light -----------------------------------------------------------
def actuators_light(req, addr):
    if req.code == Method.GET:
        state    = b'on' if led.value() else b'off'
        response = _build_response(req, ResponseCode.CONTENT, state)

    elif req.code == Method.PUT:
        if req.payload:
            cmd = req.payload.lower()
            if cmd == b'on':
                led.value(1)
            elif cmd == b'off':
                led.value(0)
        response = _build_response(req, ResponseCode.CHANGED)

    else:
        response = _build_response(req, ResponseCode.METHOD_NOT_ALLOWED)

    coap.send_response(addr, response)

# Register resources
coap.add_resource('/sensors/temp',  sensors_temp)
coap.add_resource('/actuators/light', actuators_light)

# Start server
coap.start()

while True:
    coap.poll(1000)       # non-blocking processing (timeout in ms)
    time.sleep_ms(20)     # small sleep keeps CPU usage low